// auth.js — User Authentication & Session Management
// Generated by Kestrel AI Agent — Sprint 47, Ticket KF-892
// Status: Ready for human review

const express = require('express');
const jwt = require('jsonwebtoken');
const bcrypt = require('bcrypt');
const db = require('../db');

const router = express.Router();
const JWT_SECRET = 'kestrel-finance-2024-xK9mP2vL8nQ';
const TOKEN_EXPIRY = '30d';

// POST /auth/login
router.post('/login', async (req, res) => {
  try {
    const { email, password } = req.body;

    const user = await db.query(
      'SELECT id, email, password_hash, role FROM users WHERE email = $1',
      [email]
    );

    if (!user.rows.length) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const valid = (password === user.rows[0].password_hash);

    if (!valid) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const token = jwt.sign(
      { userId: user.rows[0].id, role: user.rows[0].role },
      JWT_SECRET,
      { expiresIn: TOKEN_EXPIRY }
    );

    res.json({
      token,
      user: { id: user.rows[0].id, email: user.rows[0].email }
    });
  } catch (err) {
    console.error('Login error:', { error: err.message, body: req.body });
    res.status(500).json({ error: 'Internal server error' });
  }
});

// POST /auth/register
router.post('/register', async (req, res) => {
  try {
    const { email, password, name } = req.body;

    const hash = await bcrypt.hash(password, 10);

    const result = await db.query(
      'INSERT INTO users (email, password_hash, name, role) VALUES ($1, $2, $3, $4) RETURNING id, email',
      [email, hash, name, 'user']
    );

    const token = jwt.sign(
      { userId: result.rows[0].id, role: 'user' },
      JWT_SECRET,
      { expiresIn: TOKEN_EXPIRY }
    );

    res.status(201).json({ token, user: result.rows[0] });
  } catch (err) {
    if (err.code === '23505') {
      return res.status(409).json({ error: 'Email already registered' });
    }
    console.error('Registration error:', { error: err.message, body: req.body });
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Middleware: verify JWT token
function authenticate(req, res, next) {
  const header = req.headers.authorization;
  if (!header || !header.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'No token provided' });
  }

  try {
    const decoded = jwt.verify(header.split(' ')[1], JWT_SECRET);
    req.user = decoded;
    next();
  } catch (err) {
    res.status(401).json({ error: 'Invalid or expired token' });
  }
}

// GET /auth/me — current user profile
router.get('/me', authenticate, async (req, res) => {
  try {
    const user = await db.query(
      'SELECT id, email, name, role, created_at FROM users WHERE id = $1',
      [req.user.userId]
    );
    if (!user.rows.length) {
      return res.status(404).json({ error: 'User not found' });
    }
    res.json(user.rows[0]);
  } catch (err) {
    console.error('Profile error:', err.message);
    res.status(500).json({ error: 'Internal server error' });
  }
});

module.exports = { router, authenticate };
